class Solution:
    def onesMinusZeros(self, grid):
        m = len(grid)
        n = len(grid[0])
        diff = [[0] * n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                onesRow = sum(grid[i])
                onesCol = sum(grid[r][j] for r in range(m))
                zerosRow = n - onesRow
                zerosCol = m - onesCol
                diff[i][j] = onesRow + onesCol - zerosRow - zerosCol
        return diff

